  const { tokenValue, tokenStart: start } = parser;
  nextToken(parser, context);

  scope?.addVarOrBlock(context, tokenValue, kind, origin);

  return parser.finishNode<ESTree.Identifier>(
    {
      type: 'Identifier',
      name: tokenValue,
    },
    start,
